'use client'

import { useState, useCallback } from 'react'
import {
  DndContext,
  DragOverlay,
  closestCorners,
  PointerSensor,
  useSensor,
  useSensors,
  type DragStartEvent,
  type DragEndEvent,
  type DragOverEvent,
} from '@dnd-kit/core'
import { arrayMove } from '@dnd-kit/sortable'
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area'
import { PipelineColumn, type PipelineStage } from '@/components/pipelines/pipeline-column'
import { PipelineCard, type PipelineContactCard } from '@/components/pipelines/pipeline-card'

interface Pipeline {
  id: string
  name: string
  stages: PipelineStage[]
}

interface PipelineBoardProps {
  pipeline: Pipeline
  onMoveContact?: (contactId: string, fromStageId: string, toStageId: string) => void
  onCardClick?: (card: PipelineContactCard) => void
}

export function PipelineBoard({ pipeline, onMoveContact, onCardClick }: PipelineBoardProps) {
  const [stages, setStages] = useState<PipelineStage[]>(pipeline.stages)
  const [activeCard, setActiveCard] = useState<PipelineContactCard | null>(null)

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: { distance: 8 },
    }),
  )

  const findStageByCardId = useCallback(
    (cardId: string): PipelineStage | undefined => {
      return stages.find((stage) =>
        stage.contacts.some((c) => c.id === cardId),
      )
    },
    [stages],
  )

  const handleDragStart = (event: DragStartEvent) => {
    const cardId = event.active.id as string
    const stage = findStageByCardId(cardId)
    if (stage) {
      const card = stage.contacts.find((c) => c.id === cardId)
      if (card) setActiveCard(card)
    }
  }

  const handleDragOver = (event: DragOverEvent) => {
    const { active, over } = event
    if (!over) return

    const activeId = active.id as string
    const overId = over.id as string

    const activeStage = findStageByCardId(activeId)
    // Check if overId is a stage id or a card id
    let overStage = stages.find((s) => s.id === overId) || findStageByCardId(overId)

    if (!activeStage || !overStage || activeStage.id === overStage.id) return

    setStages((prev) => {
      const activeStageIdx = prev.findIndex((s) => s.id === activeStage.id)
      const overStageIdx = prev.findIndex((s) => s.id === overStage.id)
      const card = prev[activeStageIdx].contacts.find((c) => c.id === activeId)
      if (!card) return prev

      const updated = [...prev]
      updated[activeStageIdx] = {
        ...updated[activeStageIdx],
        contacts: updated[activeStageIdx].contacts.filter((c) => c.id !== activeId),
      }
      updated[overStageIdx] = {
        ...updated[overStageIdx],
        contacts: [...updated[overStageIdx].contacts, card],
      }
      return updated
    })
  }

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event
    setActiveCard(null)

    if (!over) return

    const activeId = active.id as string
    const overId = over.id as string

    const stage = findStageByCardId(activeId)
    if (!stage) return

    if (activeId !== overId) {
      const overIsInSameStage = stage.contacts.some((c) => c.id === overId)
      if (overIsInSameStage) {
        setStages((prev) => {
          const stageIdx = prev.findIndex((s) => s.id === stage.id)
          const oldIdx = prev[stageIdx].contacts.findIndex((c) => c.id === activeId)
          const newIdx = prev[stageIdx].contacts.findIndex((c) => c.id === overId)
          const updated = [...prev]
          updated[stageIdx] = {
            ...updated[stageIdx],
            contacts: arrayMove(updated[stageIdx].contacts, oldIdx, newIdx),
          }
          return updated
        })
      }
    }

    // Notify parent
    if (onMoveContact) {
      const newStage = findStageByCardId(activeId)
      const origStage = pipeline.stages.find((s) =>
        s.contacts.some((c) => c.id === activeId),
      )
      if (newStage && origStage && newStage.id !== origStage.id) {
        const card = newStage.contacts.find((c) => c.id === activeId)
        if (card) {
          onMoveContact(card.contactId, origStage.id, newStage.id)
        }
      }
    }
  }

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCorners}
      onDragStart={handleDragStart}
      onDragOver={handleDragOver}
      onDragEnd={handleDragEnd}
    >
      <ScrollArea className="h-full w-full">
        <div className="flex gap-4 p-6 h-full min-h-[calc(100vh-120px)]">
          {stages.map((stage) => (
            <PipelineColumn
              key={stage.id}
              stage={stage}
              onCardClick={onCardClick}
            />
          ))}
        </div>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>

      <DragOverlay>
        {activeCard ? (
          <div className="w-[280px]">
            <PipelineCard card={activeCard} />
          </div>
        ) : null}
      </DragOverlay>
    </DndContext>
  )
}

