'use client'

import { useState, useEffect, useCallback } from 'react'
import {
  Users,
  Building2,
  Plus,
  FileText,
  Mail,
  Kanban,
  Sparkles,
  ArrowRight,
  Loader2,
} from 'lucide-react'
import {
  Command,
  CommandInput,
  CommandList,
  CommandEmpty,
  CommandGroup,
  CommandItem,
  CommandSeparator,
} from '@/components/ui/command'
import { ContactAvatar } from '@/components/shared/contact-avatar'
import { ActionReview } from '@/components/ai/action-review'
import { cn } from '@/lib/utils'

interface SearchResult {
  id: string
  type: 'contact' | 'company'
  name: string
  subtitle?: string
  avatarUrl?: string | null
}

interface ChatMessage {
  id: string
  role: 'user' | 'assistant'
  content: string
}

interface ProposedAction {
  id: string
  type: string
  description: string
  details?: string
}

interface CommandBarProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  onSelectContact?: (id: string) => void
  onSelectCompany?: (id: string) => void
  onCommand?: (command: string, args?: string) => void
}

const slashCommands = [
  { command: '/add', label: 'Add a new contact', icon: Plus },
  { command: '/log', label: 'Log an interaction', icon: FileText },
  { command: '/email', label: 'Draft an email', icon: Mail },
  { command: '/pipeline', label: 'Manage pipeline', icon: Kanban },
]

export function CommandBar({
  open,
  onOpenChange,
  onSelectContact,
  onSelectCompany,
  onCommand,
}: CommandBarProps) {
  const [input, setInput] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([])
  const [proposedActions, setProposedActions] = useState<ProposedAction[]>([])
  const [isSearching, setIsSearching] = useState(false)
  const [isThinking, setIsThinking] = useState(false)

  // Keyboard shortcut
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        onOpenChange(!open)
      }
      if (e.key === 'Escape') {
        onOpenChange(false)
      }
    }
    document.addEventListener('keydown', handleKeyDown)
    return () => document.removeEventListener('keydown', handleKeyDown)
  }, [open, onOpenChange])

  // Reset state when closing
  useEffect(() => {
    if (!open) {
      setInput('')
      setResults([])
      setChatMessages([])
      setProposedActions([])
      setIsSearching(false)
      setIsThinking(false)
    }
  }, [open])

  // Search contacts/companies as user types
  useEffect(() => {
    if (!input.trim() || input.startsWith('/')) {
      setResults([])
      return
    }

    const timeout = setTimeout(async () => {
      setIsSearching(true)
      try {
        const res = await fetch(`/api/contacts?q=${encodeURIComponent(input)}&limit=5`)
        if (res.ok) {
          const data = await res.json()
          const contactResults: SearchResult[] = (data.contacts || []).map(
            (c: { id: string; name: string; email?: string; avatarUrl?: string }) => ({
              id: c.id,
              type: 'contact' as const,
              name: c.name,
              subtitle: c.email,
              avatarUrl: c.avatarUrl,
            }),
          )
          setResults(contactResults)
        }
      } catch {
        // Silently fail search
      } finally {
        setIsSearching(false)
      }
    }, 300)

    return () => clearTimeout(timeout)
  }, [input])

  const handleSendToAI = useCallback(async () => {
    if (!input.trim() || input.startsWith('/')) return

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
    }
    setChatMessages((prev) => [...prev, userMessage])
    setInput('')
    setIsThinking(true)

    try {
      const res = await fetch('/api/agent', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: input }),
      })

      if (res.ok) {
        const data = await res.json()
        const assistantMessage: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: 'assistant',
          content: data.message || 'I processed your request.',
        }
        setChatMessages((prev) => [...prev, assistantMessage])

        if (data.actions) {
          setProposedActions(data.actions)
        }
      } else {
        const assistantMessage: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: 'assistant',
          content: 'Sorry, I had trouble processing that. Please try again.',
        }
        setChatMessages((prev) => [...prev, assistantMessage])
      }
    } catch {
      const assistantMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: 'Connection error. Please try again.',
      }
      setChatMessages((prev) => [...prev, assistantMessage])
    } finally {
      setIsThinking(false)
    }
  }, [input])

  const handleApproveAction = async (action: ProposedAction) => {
    setProposedActions((prev) => prev.filter((a) => a.id !== action.id))
    // Send approval to API
    try {
      await fetch('/api/agent', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ approveAction: action }),
      })
    } catch {
      // Handle silently
    }
  }

  const handleDismissAction = (action: ProposedAction) => {
    setProposedActions((prev) => prev.filter((a) => a.id !== action.id))
  }

  const isSlashCommand = input.startsWith('/')
  const matchingCommands = isSlashCommand
    ? slashCommands.filter((cmd) =>
        cmd.command.startsWith(input.toLowerCase()),
      )
    : []
  const showChat = chatMessages.length > 0

  if (!open) return null

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center pt-[20vh]">
      {/* Backdrop */}
      <div
        className="fixed inset-0 bg-black/40 backdrop-blur-sm"
        onClick={() => onOpenChange(false)}
      />

      {/* Command palette */}
      <div className="relative w-full max-w-xl">
        <Command className="rounded-xl border border-border shadow-2xl bg-card overflow-hidden">
          <div className="flex items-center border-b border-border px-3">
            <Sparkles className="mr-2 h-4 w-4 shrink-0 text-muted-foreground" />
            <input
              className="flex h-12 w-full rounded-md bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50"
              placeholder="Search contacts, run commands, or ask Greg..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !isSlashCommand && results.length === 0) {
                  handleSendToAI()
                }
                if (e.key === 'Enter' && isSlashCommand && matchingCommands.length === 1) {
                  onCommand?.(matchingCommands[0].command)
                  onOpenChange(false)
                }
              }}
              autoFocus
            />
            {isSearching && <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />}
          </div>

          <CommandList className="max-h-[400px]">
            {/* Chat Messages */}
            {showChat && (
              <div className="px-4 py-3 space-y-3">
                {chatMessages.map((msg) => (
                  <div
                    key={msg.id}
                    className={cn(
                      'text-sm',
                      msg.role === 'user' && 'text-foreground font-medium',
                      msg.role === 'assistant' && 'text-muted-foreground',
                    )}
                  >
                    {msg.role === 'assistant' && (
                      <span className="inline-flex items-center gap-1 text-xs font-semibold text-foreground mb-0.5">
                        <Sparkles className="h-3 w-3" /> Greg
                      </span>
                    )}
                    <p>{msg.content}</p>
                  </div>
                ))}
                {isThinking && (
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Loader2 className="h-3 w-3 animate-spin" />
                    Thinking...
                  </div>
                )}
              </div>
            )}

            {/* Proposed Actions */}
            {proposedActions.length > 0 && (
              <div className="px-4 pb-3 space-y-2">
                {proposedActions.map((action) => (
                  <ActionReview
                    key={action.id}
                    type={action.type}
                    description={action.description}
                    details={action.details}
                    onApprove={() => handleApproveAction(action)}
                    onDismiss={() => handleDismissAction(action)}
                  />
                ))}
              </div>
            )}

            {/* Slash Commands */}
            {isSlashCommand && matchingCommands.length > 0 && (
              <CommandGroup heading="Commands">
                {matchingCommands.map((cmd) => (
                  <CommandItem
                    key={cmd.command}
                    value={cmd.command}
                    onSelect={() => {
                      onCommand?.(cmd.command)
                      onOpenChange(false)
                    }}
                  >
                    <cmd.icon className="mr-2 h-4 w-4" />
                    <span className="font-mono text-xs text-muted-foreground mr-2">
                      {cmd.command}
                    </span>
                    {cmd.label}
                  </CommandItem>
                ))}
              </CommandGroup>
            )}

            {/* Search Results */}
            {!isSlashCommand && results.length > 0 && (
              <>
                <CommandGroup heading="Search results">
                  {results.map((result) => (
                    <CommandItem
                      key={result.id}
                      value={result.name}
                      onSelect={() => {
                        if (result.type === 'contact') {
                          onSelectContact?.(result.id)
                        } else {
                          onSelectCompany?.(result.id)
                        }
                        onOpenChange(false)
                      }}
                    >
                      {result.type === 'contact' ? (
                        <ContactAvatar
                          name={result.name}
                          avatarUrl={result.avatarUrl}
                          size="sm"
                          className="mr-2"
                        />
                      ) : (
                        <Building2 className="mr-2 h-4 w-4 text-muted-foreground" />
                      )}
                      <div className="flex flex-col">
                        <span className="text-sm">{result.name}</span>
                        {result.subtitle && (
                          <span className="text-xs text-muted-foreground">{result.subtitle}</span>
                        )}
                      </div>
                    </CommandItem>
                  ))}
                </CommandGroup>
                <CommandSeparator />
              </>
            )}

            {/* Default actions when empty */}
            {!input && !showChat && (
              <CommandGroup heading="Quick actions">
                {slashCommands.map((cmd) => (
                  <CommandItem
                    key={cmd.command}
                    value={cmd.command}
                    onSelect={() => {
                      onCommand?.(cmd.command)
                      onOpenChange(false)
                    }}
                  >
                    <cmd.icon className="mr-2 h-4 w-4" />
                    {cmd.label}
                    <span className="ml-auto text-xs text-muted-foreground font-mono">
                      {cmd.command}
                    </span>
                  </CommandItem>
                ))}
              </CommandGroup>
            )}

            {/* Hint to ask AI */}
            {input && !isSlashCommand && results.length === 0 && !showChat && !isSearching && (
              <div className="px-4 py-6 text-center">
                <p className="text-sm text-muted-foreground">
                  Press <kbd className="rounded border border-border bg-muted px-1.5 py-0.5 font-mono text-xs">Enter</kbd> to ask Greg
                </p>
              </div>
            )}
          </CommandList>
        </Command>
      </div>
    </div>
  )
}

