'use client'

import { useState, useEffect } from 'react'
import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import { AppShell } from '@/components/layout/app-shell'
import { Sidebar } from '@/components/layout/sidebar'
import { CommandBar } from '@/components/ai/command-bar'
import { TooltipProvider } from '@/components/ui/tooltip'

interface Tag {
  id: string
  name: string
  color: string
  count: number
}

export default function AppLayout({ children }: { children: React.ReactNode }) {
  const { data: session, status } = useSession()
  const router = useRouter()
  const [commandBarOpen, setCommandBarOpen] = useState(false)
  const [tags, setTags] = useState<Tag[]>([])

  // Redirect to login if unauthenticated
  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/login')
    }
  }, [status, router])

  // Fetch tags for sidebar
  useEffect(() => {
    if (status === 'authenticated') {
      fetch('/api/tags')
        .then((res) => res.ok ? res.json() : { tags: [] })
        .then((data) => setTags(data.tags || []))
        .catch(() => {})
    }
  }, [status])

  const handleCommand = (command: string) => {
    switch (command) {
      case '/add':
        router.push('/contacts?action=add')
        break
      case '/log':
        router.push('/contacts?action=log')
        break
      case '/email':
        // Future: open email draft
        break
      case '/pipeline':
        router.push('/pipelines')
        break
    }
  }

  if (status === 'loading') {
    return (
      <div className="flex h-screen items-center justify-center bg-background">
        <div className="flex flex-col items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-full bg-foreground text-primary-foreground text-lg font-bold">
            G
          </div>
          <p className="text-sm text-muted-foreground">Loading...</p>
        </div>
      </div>
    )
  }

  if (status === 'unauthenticated') {
    return null
  }

  return (
    <TooltipProvider>
      <AppShell
        sidebar={
          <Sidebar
            tags={tags}
            onOpenCommandBar={() => setCommandBarOpen(true)}
            user={session?.user}
            workspaceName="Greg"
          />
        }
      >
        {children}
      </AppShell>
      <CommandBar
        open={commandBarOpen}
        onOpenChange={setCommandBarOpen}
        onSelectContact={(id) => router.push(`/contacts?selected=${id}`)}
        onSelectCompany={(id) => router.push(`/companies?selected=${id}`)}
        onCommand={handleCommand}
      />
    </TooltipProvider>
  )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { useSearchParams, useRouter } from 'next/navigation'
import { Plus, Users } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog'
import { ContactsTable, type ContactRow } from '@/components/contacts/contacts-table'
import { ContactSheet } from '@/components/contacts/contact-sheet'
import { ContactForm } from '@/components/contacts/contact-form'
import { DataTableToolbar } from '@/components/shared/data-table-toolbar'
import { EmptyState } from '@/components/shared/empty-state'
import { Skeleton } from '@/components/ui/skeleton'
import { toast } from 'sonner'

interface Tag {
  id: string
  name: string
  color: string
}

interface Company {
  id: string
  name: string
}

export default function ContactsPage() {
  const searchParams = useSearchParams()
  const router = useRouter()

  const [contacts, setContacts] = useState<ContactRow[]>([])
  const [loading, setLoading] = useState(true)
  const [searchValue, setSearchValue] = useState('')
  const [addDialogOpen, setAddDialogOpen] = useState(false)
  const [selectedContact, setSelectedContact] = useState<ContactRow | null>(null)
  const [sheetOpen, setSheetOpen] = useState(false)
  const [contactDetail, setContactDetail] = useState<any>(null)
  const [companies, setCompanies] = useState<Company[]>([])
  const [availableTags, setAvailableTags] = useState<Tag[]>([])
  const [isSubmitting, setIsSubmitting] = useState(false)

  // Check for action params
  useEffect(() => {
    if (searchParams.get('action') === 'add') {
      setAddDialogOpen(true)
    }
  }, [searchParams])

  // Fetch contacts
  useEffect(() => {
    setLoading(true)
    fetch('/api/contacts')
      .then((res) => res.ok ? res.json() : { contacts: [] })
      .then((data) => setContacts(data.contacts || []))
      .catch(() => {})
      .finally(() => setLoading(false))
  }, [])

  // Fetch companies and tags for form
  useEffect(() => {
    fetch('/api/companies')
      .then((res) => res.ok ? res.json() : { companies: [] })
      .then((data) => setCompanies(data.companies || []))
      .catch(() => {})

    fetch('/api/tags')
      .then((res) => res.ok ? res.json() : { tags: [] })
      .then((data) => setAvailableTags(data.tags || []))
      .catch(() => {})
  }, [])

  // Filter contacts by search
  const filteredContacts = useMemo(() => {
    if (!searchValue) return contacts
    const q = searchValue.toLowerCase()
    return contacts.filter(
      (c) =>
        c.name.toLowerCase().includes(q) ||
        c.email?.toLowerCase().includes(q) ||
        c.company?.name.toLowerCase().includes(q) ||
        c.title?.toLowerCase().includes(q),
    )
  }, [contacts, searchValue])

  const handleRowClick = async (contact: ContactRow) => {
    setSelectedContact(contact)
    setSheetOpen(true)
    // Fetch full contact details
    try {
      const res = await fetch(`/api/contacts/${contact.id}`)
      if (res.ok) {
        const data = await res.json()
        setContactDetail(data.contact)
      }
    } catch {
      // Show basic data
      setContactDetail(contact)
    }
  }

  const handleAddContact = async (formData: any) => {
    setIsSubmitting(true)
    try {
      const res = await fetch('/api/contacts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      })
      if (res.ok) {
        const data = await res.json()
        setContacts((prev) => [data.contact, ...prev])
        setAddDialogOpen(false)
        toast.success('Contact added successfully')
      } else {
        toast.error('Failed to add contact')
      }
    } catch {
      toast.error('Failed to add contact')
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleDeleteContact = async (contact: any) => {
    try {
      const res = await fetch(`/api/contacts/${contact.id}`, { method: 'DELETE' })
      if (res.ok) {
        setContacts((prev) => prev.filter((c) => c.id !== contact.id))
        setSheetOpen(false)
        toast.success('Contact deleted')
      }
    } catch {
      toast.error('Failed to delete contact')
    }
  }

  return (
    <div className="flex flex-col h-full">
      {/* Page Header */}
      <div className="flex items-center justify-between border-b border-border px-6 py-4">
        <div>
          <h1 className="text-xl font-semibold text-foreground">Contacts</h1>
          <p className="text-sm text-muted-foreground">
            {contacts.length} {contacts.length === 1 ? 'contact' : 'contacts'}
          </p>
        </div>
        <Button onClick={() => setAddDialogOpen(true)}>
          <Plus className="h-4 w-4 mr-1" />
          Add contact
        </Button>
      </div>

      {/* Toolbar */}
      <div className="px-6 py-3 border-b border-border">
        <DataTableToolbar
          searchValue={searchValue}
          onSearchChange={setSearchValue}
          placeholder="Search contacts..."
        />
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto">
        {loading ? (
          <div className="p-6 space-y-3">
            {Array.from({ length: 5 }).map((_, i) => (
              <div key={i} className="flex items-center gap-3">
                <Skeleton className="h-8 w-8 rounded-full" />
                <div className="space-y-1.5 flex-1">
                  <Skeleton className="h-4 w-48" />
                  <Skeleton className="h-3 w-32" />
                </div>
              </div>
            ))}
          </div>
        ) : filteredContacts.length === 0 && !searchValue ? (
          <EmptyState
            icon={Users}
            title="No contacts yet"
            description="Add your first contact to start building your network."
            action={{
              label: 'Add contact',
              onClick: () => setAddDialogOpen(true),
            }}
          />
        ) : (
          <ContactsTable data={filteredContacts} onRowClick={handleRowClick} />
        )}
      </div>

      {/* Add Contact Dialog */}
      <Dialog open={addDialogOpen} onOpenChange={setAddDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Add contact</DialogTitle>
            <DialogDescription>Add a new contact to your CRM.</DialogDescription>
          </DialogHeader>
          <ContactForm
            companies={companies}
            availableTags={availableTags}
            onSubmit={handleAddContact}
            onCancel={() => setAddDialogOpen(false)}
            isLoading={isSubmitting}
          />
        </DialogContent>
      </Dialog>

      {/* Contact Detail Sheet */}
      <ContactSheet
        contact={contactDetail}
        open={sheetOpen}
        onOpenChange={setSheetOpen}
        onEdit={(contact) => {
          setSheetOpen(false)
          // Could open edit dialog
        }}
        onDelete={handleDeleteContact}
        onLogInteraction={(contact) => {
          // Could open log interaction dialog
        }}
      />
    </div>
  )
}

