'use client'

import { useState, useEffect } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { ArrowLeft, Settings } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Skeleton } from '@/components/ui/skeleton'
import { PipelineBoard } from '@/components/pipelines/pipeline-board'
import type { PipelineStage } from '@/components/pipelines/pipeline-column'
import type { PipelineContactCard } from '@/components/pipelines/pipeline-card'

interface PipelineData {
  id: string
  name: string
  description?: string | null
  stages: PipelineStage[]
}

export default function PipelineBoardPage() {
  const params = useParams()
  const router = useRouter()
  const [pipeline, setPipeline] = useState<PipelineData | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!params.id) return
    setLoading(true)
    fetch(`/api/pipelines/${params.id}`)
      .then((res) => res.ok ? res.json() : null)
      .then((data) => {
        if (data?.pipeline) {
          setPipeline(data.pipeline)
        }
      })
      .catch(() => {})
      .finally(() => setLoading(false))
  }, [params.id])

  const handleMoveContact = async (contactId: string, fromStageId: string, toStageId: string) => {
    try {
      await fetch(`/api/pipelines/${params.id}/move`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ contactId, fromStageId, toStageId }),
      })
    } catch {
      // Handle error silently or with toast
    }
  }

  const handleCardClick = (card: PipelineContactCard) => {
    router.push(`/contacts?selected=${card.contactId}`)
  }

  if (loading) {
    return (
      <div className="flex flex-col h-full">
        <div className="flex items-center gap-3 border-b border-border px-6 py-4">
          <Skeleton className="h-6 w-6" />
          <Skeleton className="h-6 w-48" />
        </div>
        <div className="flex gap-4 p-6 overflow-x-auto">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className="w-[300px] min-w-[300px]">
              <Skeleton className="h-8 w-32 mb-3" />
              <div className="space-y-2">
                <Skeleton className="h-20 w-full rounded-lg" />
                <Skeleton className="h-20 w-full rounded-lg" />
              </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  if (!pipeline) {
    return (
      <div className="flex flex-col items-center justify-center h-full">
        <p className="text-muted-foreground">Pipeline not found.</p>
        <Button variant="ghost" className="mt-2" onClick={() => router.push('/pipelines')}>
          <ArrowLeft className="h-4 w-4 mr-1" />
          Back to pipelines
        </Button>
      </div>
    )
  }

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-border px-6 py-4">
        <div className="flex items-center gap-3">
          <Button variant="ghost" size="icon" onClick={() => router.push('/pipelines')}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h1 className="text-xl font-semibold text-foreground">{pipeline.name}</h1>
            {pipeline.description && (
              <p className="text-sm text-muted-foreground">{pipeline.description}</p>
            )}
          </div>
        </div>
        <Button variant="outline" size="sm">
          <Settings className="h-4 w-4 mr-1" />
          Settings
        </Button>
      </div>

      {/* Board */}
      <div className="flex-1 overflow-hidden">
        <PipelineBoard
          pipeline={pipeline}
          onMoveContact={handleMoveContact}
          onCardClick={handleCardClick}
        />
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { Activity as ActivityIcon } from 'lucide-react'
import { ActivityTimeline } from '@/components/activity/activity-timeline'
import { DataTableToolbar } from '@/components/shared/data-table-toolbar'
import { EmptyState } from '@/components/shared/empty-state'
import { Skeleton } from '@/components/ui/skeleton'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import { cn } from '@/lib/utils'

const activityTypes = [
  { value: '', label: 'All' },
  { value: 'note', label: 'Notes' },
  { value: 'email_sent', label: 'Emails sent' },
  { value: 'email_received', label: 'Emails received' },
  { value: 'call', label: 'Calls' },
  { value: 'meeting', label: 'Meetings' },
  { value: 'stage_change', label: 'Stage changes' },
]

interface ActivityItemData {
  id: string
  type: string
  title?: string | null
  body?: string | null
  occurredAt: string
  contact?: { id: string; name: string } | null
}

export default function ActivityPage() {
  const [activities, setActivities] = useState<ActivityItemData[]>([])
  const [loading, setLoading] = useState(true)
  const [searchValue, setSearchValue] = useState('')
  const [typeFilter, setTypeFilter] = useState('')

  useEffect(() => {
    setLoading(true)
    fetch('/api/interactions')
      .then((res) => res.ok ? res.json() : { interactions: [] })
      .then((data) => setActivities(data.interactions || []))
      .catch(() => {})
      .finally(() => setLoading(false))
  }, [])

  const filteredActivities = useMemo(() => {
    let filtered = activities
    if (typeFilter) {
      filtered = filtered.filter((a) => a.type === typeFilter)
    }
    if (searchValue) {
      const q = searchValue.toLowerCase()
      filtered = filtered.filter(
        (a) =>
          a.title?.toLowerCase().includes(q) ||
          a.body?.toLowerCase().includes(q) ||
          a.contact?.name.toLowerCase().includes(q),
      )
    }
    return filtered
  }, [activities, searchValue, typeFilter])

  return (
    <div className="flex flex-col h-full">
      {/* Page Header */}
      <div className="flex items-center justify-between border-b border-border px-6 py-4">
        <div>
          <h1 className="text-xl font-semibold text-foreground">Activity</h1>
          <p className="text-sm text-muted-foreground">
            Recent interactions and updates
          </p>
        </div>
      </div>

      {/* Toolbar */}
      <div className="px-6 py-3 border-b border-border">
        <DataTableToolbar
          searchValue={searchValue}
          onSearchChange={setSearchValue}
          placeholder="Search activity..."
        >
          <div className="flex items-center gap-1.5">
            {activityTypes.map((type) => (
              <Button
                key={type.value}
                variant={typeFilter === type.value ? 'default' : 'outline'}
                size="sm"
                className="h-7 text-xs"
                onClick={() => setTypeFilter(type.value)}
              >
                {type.label}
              </Button>
            ))}
          </div>
        </DataTableToolbar>
      </div>

      {/* Content */}
      <ScrollArea className="flex-1">
        <div className="max-w-2xl mx-auto px-6 py-6">
          {loading ? (
            <div className="space-y-4">
              {Array.from({ length: 5 }).map((_, i) => (
                <div key={i} className="flex items-start gap-3">
                  <Skeleton className="h-8 w-8 rounded-full" />
                  <div className="space-y-1.5 flex-1">
                    <Skeleton className="h-4 w-48" />
                    <Skeleton className="h-3 w-full" />
                  </div>
                </div>
              ))}
            </div>
          ) : filteredActivities.length === 0 ? (
            <EmptyState
              icon={ActivityIcon}
              title="No activity yet"
              description="Activity will appear here as you log interactions and make changes."
            />
          ) : (
            <ActivityTimeline items={filteredActivities} />
          )}
        </div>
      </ScrollArea>
    </div>
  )
}
